/**
 * @name String reference value used directly in XHTML attribute output
 * @description Track where link reference strings flow into XHTML attribute output
 * @kind path-problem
 * @problem.severity error
 * @id java/xwiki-link-ref-to-href
 * @tags security
 *       external/cwe/cwe-079
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module LinkHrefConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Resource reference getReference() calls - user-controlled link destination
    exists(MethodCall mc |
      mc.getMethod().hasName("getReference") and
      mc.getMethod().getDeclaringType().getQualifiedName().matches("org.xwiki.rendering.listener.reference%")
      and source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // printXMLAttribute with href/src values
    exists(MethodCall mc |
      (mc.getMethod().hasName("printXMLAttribute") or
       mc.getMethod().hasName("setAttribute") or
       mc.getMethod().hasName("printRaw"))
      and sink.asExpr() = mc.getAnArgument()
      and mc.getMethod().getDeclaringType().getQualifiedName().matches("org.xwiki.rendering%")
    )
  }
}

module LinkHrefFlow = TaintTracking::Global<LinkHrefConfig>;
import LinkHrefFlow::PathGraph

from LinkHrefFlow::PathNode source, LinkHrefFlow::PathNode sink
where LinkHrefFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Link reference value flows into HTML attribute output without protocol validation $@.", source.getNode(), "source"

/**
 * @name HTMLMacro clean=false - raw HTML content passed to RawBlock without sanitization
 * @description When clean=false, HTMLMacro wraps content in a RawBlock bypassing all sanitization
 * @kind path-problem
 * @problem.severity error
 * @id java/xwiki-htmlmacro-rawblock-xss
 * @tags security
 *       external/cwe/cwe-079
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module RawBlockConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // The macro content string parameter in HTMLMacro.execute
    exists(Parameter p |
      p.getCallable().getDeclaringType().hasQualifiedName(
        "org.xwiki.rendering.internal.macro.html", "HTMLMacro")
      and p.getCallable().hasName("execute")
      and source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Content passed to RawBlock constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName(
        "org.xwiki.rendering.block", "RawBlock")
      and sink.asExpr() = ce.getArgument(0)
    )
  }
}

module RawBlockFlow = TaintTracking::Global<RawBlockConfig>;
import RawBlockFlow::PathGraph

from RawBlockFlow::PathNode source, RawBlockFlow::PathNode sink
where RawBlockFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "HTMLMacro content flows to RawBlock constructor without sanitization when clean=false $@.", source.getNode(), "macro content"
